import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import { matchesSearchQuery } from './matchesSearchQuery';

describe('matchesSearchQuery', () => {
  it('should handle happy path: returns true when query matches note content', () => {
    const note = { title: 'Meeting Notes', body: 'Discuss project roadmap' };
    const query = 'project';
    expect(matchesSearchQuery(note, query)).toBe(true);
  });

  it('should handle edge case: returns false when query is an empty string', () => {
    const note = { title: 'Shopping List', body: 'Eggs, Milk, Bread' };
    const query = '';
    expect(matchesSearchQuery(note, query)).toBe(false);
  });

  it('should handle null/empty: returns false when note or query is nullish or empty', () => {
    const note = null;
    const query = null;
    expect(matchesSearchQuery(note as any, query as any)).toBe(false);
    expect(matchesSearchQuery(undefined, undefined)).toBe(false);
    expect(matchesSearchQuery({ title: '', body: '' }, '')).toBe(false);
  });
});

